/// What an action DOES (spec `kind`): a client-side behaviour, a domain write, an
/// auth-provider call outside the domain, or a declared gap with no backing mutation.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub enum ActionKind {
    Auth,
    Client,
    Gap,
    Mutation,
}

impl ActionKind {
    /// The spec `kind` token — 1:1 with the DSL.
    pub fn as_str(&self) -> &'static str {
        match self {
            ActionKind::Auth => "auth",
            ActionKind::Client => "client",
            ActionKind::Gap => "gap",
            ActionKind::Mutation => "mutation",
        }
    }
}

